import numpy as np

class SpectralNorm:
    def __init__(self, n_power_iters: int = 1):
        self.n_power_iters = n_power_iters
        self._u = None

    def _reshape(self, W: np.ndarray) -> np.ndarray:
        if W.ndim > 2:
            return W.reshape(W.shape[0], -1)
        return W

    def _power_iter(self, W_mat: np.ndarray) -> tuple:
        if self._u is None or self._u.shape[0] != W_mat.shape[0]:
            self._u = np.random.randn(W_mat.shape[0])
            self._u = self._u / (np.linalg.norm(self._u) + 1e-12)
        u = self._u
        for _ in range(self.n_power_iters):
            v = W_mat.T @ u
            v = v / (np.linalg.norm(v) + 1e-12)
            u = W_mat @ v
            u = u / (np.linalg.norm(u) + 1e-12)
        self._u = u
        sigma = float(u @ W_mat @ v)
        return sigma, u, v

    def sigma(self, W: np.ndarray) -> float:
        W_mat = self._reshape(W)
        s, _, _ = self._power_iter(W_mat.copy())
        return s

    def normalize(self, W: np.ndarray) -> np.ndarray:
        W_mat = self._reshape(W)
        s, _, _ = self._power_iter(W_mat)
        return W / (s + 1e-12)
